// // This module implements a 2-bit shift register with parallel loading capability.
// It has a 2-bit input, a clock signal, a load enable signal, and a shift enable signal.
// When the load enable is high, the input should be loaded into the register.
// When the shift enable is high, the register should shift right, and the least significant bit should be filled with 1.
module shift_register(  
    input clk,  
    input load,  
    input shift,  
    input [1:0] data_in,  
    output reg [1:0] data_out  
);  
    always @(posedge clk) begin  
        if (load)  
            data_out <= data_in;  
        else if (shift)  
            data_out <= {data_out[0], 1'b0};  
    end  
endmodule

